@RestController
@RequestMapping("/orders")
public class OrderController {

    @Autowired
    private OrderService orderService;

    @GetMapping("/{orderId}")
    public ResponseEntity<OrderDetails> getOrderDetails(@PathVariable Long orderId) {
        User user = (User) SecurityContextHolder.getContext().getAuthentication().getPrincipal();
        OrderDetails orderDetails = orderService.getOrderDetails(orderId, user);
        return new ResponseEntity<>(orderDetails, HttpStatus.OK);
    }
}

@Service
public class OrderService {

    @Autowired
    private OrderRepository orderRepository;

    public OrderDetails getOrderDetails(Long orderId, User user) {
        Optional<Order> orderOptional = orderRepository.findById(orderId);
        if (orderOptional.isPresent()) {
            Order order = orderOptional.get();
            if (order.getUser().getId().equals(user.getId())) {
                return new OrderDetails(order);
            } else {
                throw new AccessDeniedException("Access denied for this order");
            }
        } else {
            throw new OrderNotFoundException("Order not found");
        }
    }
}

